const all = $input.all().map(i => i.json);
const recent30 = all.filter(r => { const d = new Date(r.date); const ago = new Date(); ago.setDate(ago.getDate()-30); return d >= ago; });
const score = (r) => parseInt(r.score || 0);
const npsOf = (arr) => { if (!arr.length) return null; const p = arr.filter(r=>score(r)>=9).length/arr.length*100; const d = arr.filter(r=>score(r)<=6).length/arr.length*100; return Math.round(p-d); };
const nps = npsOf(recent30); const npsAll = npsOf(all);
const prev30 = all.filter(r => { const d=new Date(r.date); const s=new Date(); s.setDate(s.getDate()-60); const e=new Date(); e.setDate(e.getDate()-30); return d>=s && d<e; });
const prevNps = npsOf(prev30);
const change = prevNps !== null ? nps - prevNps : null;
const alertThreshold = parseInt($env.NPS_ALERT_CHANGE || 5);
return [{ json: { date: new Date().toISOString().slice(0,10), nps_30d: nps, nps_all_time: npsAll, prev_30d_nps: prevNps, change_from_prev: change, alert: change !== null && change <= -alertThreshold, total_responses: all.length, recent_count: recent30.length } }];

